(async () => {

  // ── DETECT ACTOR / TARGET ─────────────────────────────────────────────────
  let actorToken = canvas.tokens.controlled[0];
  if (!actorToken) { actorToken = canvas.tokens.placeables.find(t => t.actor && t.actor.isOwner); }
  if (!actorToken) { ui.notifications.warn('No token found. Select your token first.'); return; }
  const actor = actorToken.actor;
  const isPC  = actor.type === 'character';

  if (!isPC) { ui.notifications.warn('Spells panel is for PC characters only.'); return; }

  let targetToken = [...game.user.targets][0] || null;
  if (!targetToken) {
    const gs   = canvas.grid.size;
    const pool = canvas.tokens.placeables.filter(t => {
      if (t.id === actorToken.id || !t.actor) return false;
      if (!game.user.isGM && !t.visible) return false;
      return t.actor.type === 'npc';
    });
    if (pool.length) {
      targetToken = pool.sort((a, b) => {
        const da = Math.hypot((a.center.x - actorToken.center.x) / gs, (a.center.y - actorToken.center.y) / gs);
        const db = Math.hypot((b.center.x - actorToken.center.x) / gs, (b.center.y - actorToken.center.y) / gs);
        return da - db;
      })[0];
    }
  }

  const gs   = canvas.grid.size;
  const dist = targetToken
    ? Math.hypot((targetToken.center.x - actorToken.center.x) / gs, (targetToken.center.y - actorToken.center.y) / gs)
    : null;
  const armorType = (targetToken?.actor?.system?.attributes?.armor) || 'none';

  // ── COLLECT SPELL ACTIONS ─────────────────────────────────────────────────
  const abilityMap = {};
  const lvl = actor.system.classData?.levels?.length ?? 1;
  for (const [key, val] of Object.entries(actor.system.abilities || {})) { abilityMap['@' + key] = String(val.mod); }
  abilityMap['@level'] = String(lvl);

  function resolveFormula(raw) {
    let expr = raw.replace(/@[a-zA-Z]+/g, k => abilityMap[k] ?? '0');
    const dm = expr.match(/\d+d\d+/g) || [];
    const me = expr.replace(/\d+d\d+/g, '0');
    let mod = 0;
    try { mod = Math.round(Function('return (' + me.replace(/floor/g, 'Math.floor') + ')')()) ; } catch(e) {}
    return dm.join('+') + (mod > 0 ? '+' + mod : mod < 0 ? String(mod) : '');
  }

  const actions = actor.items.filter(i => i.type === 'spell').map(i => {
    const fx = (i.system.activation?.effects || []).find(e => e.type === 'damage' && e.formula);
    if (!fx) return null;
    const raw = fx.formula;
    const sel = i.system.properties?.selected || [];
    const rangeMax = sel.includes('range') && i.system.properties.range?.max != null
      ? i.system.properties.range.max
      : (sel.includes('reach') && i.system.properties.reach?.max != null
        ? i.system.properties.reach.max : 1);
    const rangeMin = sel.includes('range') && i.system.properties.range?.min != null
      ? i.system.properties.range.min : 1;
    const tag = rangeMax > 1 ? '[range ' + rangeMax + 'sq]' : '[reach]';
    return { id: i.id, name: i.name, raw, formula: resolveFormula(raw), rangeMin, rangeMax, isRanged: rangeMax > 1, tag };
  }).filter(Boolean);

  if (!actions.length) { ui.notifications.warn('No damage spells found for ' + actor.name + '.'); return; }

  window._nimbleShowCard(actorToken, targetToken, dist, armorType, actions, '\u2728 Spells');

})();
